function validateDates(){const e=document.getElementById("hmeromhnia_proslhpshs"),t=document.getElementById("hmeromhnia_allaghs_symbashs"),a=new Date(e.value),n=new Date(t.value);e.value&&t.value&&n<a&&(alert("Η ημερομηνία αλλαγής σύμβασης δεν μπορεί να είναι μικρότερη της ημερομηνία πρόσληψης."),t.value=e.value,t.focus())}document.addEventListener("DOMContentLoaded",function(){document.getElementById("hmeromhnia_proslhpshs"),document.getElementById("hmeromhnia_allaghs_symbashs").addEventListener("blur",function(){validateDates()})});